arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(CustomerData.Churned),
        featureColumnName: "Features"));

var model = pipeline.Fit(dataView);

// Evaluate on training data (small dataset — for demonstration)
var predictions = model.Transform(dataView);
var metrics = mlContext.BinaryClassification.Evaluate(predictions,
    labelColumnName: nameof(CustomerData.Churned));

Console.WriteLine($"Model trained — Accuracy: {metrics.Accuracy:P2}, AUC: {metrics.AreaUnderRocCurve:P2}");

var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// --- Endpoints ---
app.MapGet("/", () => new
{
    accuracy = metrics.Accuracy,
    auc = metrics.AreaUnderRocCurve,
    message = "POST /predict with { age, income, region, purchaseHistory }"
});

app.MapPost("/predict", (CustomerInput input) =>
{
    var customer = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };

    var result = predictionEngine.Predict(customer);
    return new
    {
        willChurn = result.PredictedLabel,
        probability = result.Probability,
        score = result.Score
    };
});

app.Run();

// --- Data models ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

